mapper.select:
SELECT t.terms_no, t.app_type_cd, a.code_nm AS app_type_nm, t.terms_type_cd, tt.code_nm AS terms_type_nm, t.required_yn, t.version, t.use_yn, t.created_at, t.created_by FROM terms t LEFT JOIN com_code a ON a.grp_cd = 'TERMS_APP_TYPE' AND a.code = t.app_type_cd LEFT JOIN com_code tt ON tt.grp_cd = 'TERMS_TYPE' AND tt.code = t.terms_type_cd WHERE t.use_yn = 'Y'
AND t.app_type_cd = #{searchAppType}
AND t.terms_type_cd = #{searchTermsType}
ORDER BY t.app_type_cd ASC, t.terms_type_cd ASC, t.version DESC
